const express = require('express');
const https = require('https');
const http = require('http');
const { URL } = require('url');
const crypto = require('crypto');

const app = express();
app.use(express.json({ limit: '1mb' }));
app.use(express.urlencoded({ extended: true, limit: '1mb' }));

const ALLOWED_PROTOCOLS = ['http:', 'https:'];
const BLOCKED_IP_RANGES = [
  { start: '10.0.0.0', end: '10.255.255.255' },
  { start: '172.16.0.0', end: '172.31.255.255' },
  { start: '192.168.0.0', end: '192.168.255.255' },
  { start: '127.0.0.0', end: '127.255.255.255' },
  { start: '169.254.0.0', end: '169.254.255.255' },
  { start: '::1', end: '::1' },
  { start: 'fc00::', end: 'fdff:ffff:ffff:ffff:ffff:ffff:ffff:ffff' },
  { start: 'fe80::', end: 'febf:ffff:ffff:ffff:ffff:ffff:ffff:ffff' }
];

const BLOCKED_DOMAINS = [
  'localhost',
  'metadata.google.internal',
  '169.254.169.254',
  'metadata.azure.com'
];

const MAX_REDIRECTS = 3;
const REQUEST_TIMEOUT = 10000;
const MAX_RESPONSE_SIZE = 10 * 1024 * 1024;

function ipToLong(ip) {
  const parts = ip.split('.');
  if (parts.length !== 4) return null;
  return parts.reduce((acc, octet) => (acc << 8) + parseInt(octet, 10), 0) >>> 0;
}

function isPrivateIP(ip) {
  const ipLong = ipToLong(ip);
  if (!ipLong) return true;
  
  for (const range of BLOCKED_IP_RANGES) {
    const startLong = ipToLong(range.start);
    const endLong = ipToLong(range.end);
    if (startLong && endLong && ipLong >= startLong && ipLong <= endLong) {
      return true;
    }
  }
  return false;
}

function validateUrl(urlString) {
  try {
    const parsedUrl = new URL(urlString);
    
    if (!ALLOWED_PROTOCOLS.includes(parsedUrl.protocol)) {
      throw new Error('Invalid protocol');
    }
    
    const hostname = parsedUrl.hostname.toLowerCase();
    
    if (BLOCKED_DOMAINS.includes(hostname)) {
      throw new Error('Blocked domain');
    }
    
    if (/^\d+\.\d+\.\d+\.\d+$/.test(hostname)) {
      if (isPrivateIP(hostname)) {
        throw new Error('Private IP address not allowed');
      }
    }
    
    if (parsedUrl.username || parsedUrl.password) {
      throw new Error('URL credentials not allowed');
    }
    
    return parsedUrl;
  } catch (error) {
    throw new Error('Invalid URL: ' + error.message);
  }
}

function makeRequest(url, method, headers, body, redirectCount = 0) {
  return new Promise((resolve, reject) => {
    if (redirectCount > MAX_REDIRECTS) {
      return reject(new Error('Too many redirects'));
    }

    const parsedUrl = validateUrl(url);
    const protocol = parsedUrl.protocol === 'https:' ? https : http;
    
    const sanitizedHeaders = {};
    const allowedHeaders = ['content-type', 'accept', 'user-agent', 'authorization'];
    
    for (const [key, value] of Object.entries(headers)) {
      const lowerKey = key.toLowerCase();
      if (allowedHeaders.includes(lowerKey)) {
        sanitizedHeaders[key] = value;
      }
    }
    
    delete sanitizedHeaders['host'];
    delete sanitizedHeaders['connection'];
    
    const options = {
      method: method,
      headers: sanitizedHeaders,
      timeout: REQUEST_TIMEOUT,
      rejectUnauthorized: true
    };

    const req = protocol.request(parsedUrl, options, (res) => {
      if (res.statusCode >= 300 && res.statusCode < 400 && res.headers.location) {
        const redirectUrl = new URL(res.headers.location, url).href;
        return makeRequest(redirectUrl, method, headers, body, redirectCount + 1)
          .then(resolve)
          .catch(reject);
      }

      let data = [];
      let totalSize = 0;

      res.on('data', (chunk) => {
        totalSize += chunk.length;
        if (totalSize > MAX_RESPONSE_SIZE) {
          req.destroy();
          reject(new Error('Response too large'));
          return;
        }
        data.push(chunk);
      });

      res.on('end', () => {
        resolve({
          statusCode: res.statusCode,
          headers: res.headers,
          body: Buffer.concat(data)
        });
      });
    });

    req.on('error', (error) => {
      reject(error);
    });

    req.on('timeout', () => {
      req.destroy();
      reject(new Error('Request timeout'));
    });

    if (body && (method === 'POST' || method === 'PUT' || method === 'PATCH')) {
      req.write(body);
    }

    req.end();
  });
}

app.post('/proxy', async (req, res) => {
  try {
    const { url, method = 'GET', headers = {}, body } = req.body;

    if (!url) {
      return res.status(400).json({ error: 'URL is required' });
    }

    const allowedMethods = ['GET', 'POST', 'PUT', 'PATCH', 'DELETE', 'HEAD'];
    const requestMethod = method.toUpperCase();
    
    if (!allowedMethods.includes(requestMethod)) {
      return res.status(400).json({ error: 'Invalid HTTP method' });
    }

    validateUrl(url);

    const requestBody = body ? (typeof body === 'string' ? body : JSON.stringify(body)) : null;

    const response = await makeRequest(url, requestMethod, headers, requestBody);

    const safeHeaders = {};
    const allowedResponseHeaders = ['content-type', 'content-length', 'cache-control', 'etag'];
    
    for (const [key, value] of Object.entries(response.headers)) {
      if (allowedResponseHeaders.includes(key.toLowerCase())) {
        safeHeaders[key] = value;
      }
    }

    res.status(response.statusCode);
    Object.entries(safeHeaders).forEach(([key, value]) => {
      res.setHeader(key, value);
    });
    
    res.send(response.body);

  } catch (error) {
    console.error('Proxy error:', error.message);
    res.status(500).json({ 
      error: 'Proxy request failed',
      message: error.message 
    });
  }
});

